#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int cnt=0, x;
        for(int i=0;i<N;i++){
            scanf("%d",&x);
            if(x>=1000) cnt++;
        }
        printf("%d\n",cnt);
    }
    return 0;
}

